public async Task GetProductByIdAsync_WhenProductNotFound_ThrowsNotFoundException()
{
    // Arrange
    var mockRepo = new Mock<IProductRepository>();
    mockRepo.Setup(repo => repo.GetByIdAsync(99))
            .ReturnsAsync((Product)null);

    var service = new ProductService(mockRepo.Object);

    // Act & Assert
    var exception = await Assert.ThrowsAsync<NotFoundException>(
        () => service.GetProductByIdAsync(99)
    );

    Assert.Equal("Product with id 99 not found", exception.Message);
}
