[Fact]
public async Task ProcessOrderAsync_WhenPaymentSucceeds_UpdatesStatusAndReturnsTrue()
{
    // Arrange
    var order = new Order { Id = 1, TotalAmount = 100, Status = "Pending" };

    var mockOrderRepo = new Mock<IOrderRepository>();
    mockOrderRepo.Setup(repo => repo.UpdateStatusAsync(1, "Paid"))
                 .Returns(Task.CompletedTask);

    var mockPayment = new Mock<IPaymentGateway>();
    mockPayment.Setup(p => p.ChargeAsync(100))
               .ReturnsAsync(true);

    var service = new OrderService(mockOrderRepo.Object, mockPayment.Object);

    // Act
    var result = await service.ProcessOrderAsync(order);

    // Assert
    Assert.True(result);
    mockPayment.Verify(p => p.ChargeAsync(100), Times.Once);
    mockOrderRepo.Verify(r => r.UpdateStatusAsync(1, "Paid"), Times.Once);
}
```

